 margin-left:0.3rem; }\n    .tele-bar[_ngcontent-%COMP%] { margin-top:0.6rem; height:3px; background:rgba(0,255,231,0.1); border-radius:2px; overflow:hidden; }\n    .tele-bar-fill[_ngcontent-%COMP%] { height:100%; background:var(--neon); border-radius:2px; transition:width 0.08s linear; box-shadow:0 0 6px var(--neon); }\n    .tele-bar-fill.gripper[_ngcontent-%COMP%] { background:var(--neon2); box-shadow:0 0 6px var(--neon2); }\n    .sys-status-card[_ngcontent-%COMP%] { background:rgba(255,107,53,0.03); border-color:rgba(255,107,53,0.15); }\n    .sys-status-row[_ngcontent-%COMP%]  { display:flex; align-items:center; gap:0.5rem; margin-top:0.3rem; }\n    .sys-status-text[_ngcontent-%COMP%] { font-family:'Share Tech Mono',monospace; font-size:0.85rem; color:var(--neon); }\n\n    .history-list[_ngcontent-%COMP%] { max-height:200px; overflow-y:auto; }\n    .history-list[_ngcontent-%COMP%]::-webkit-scrollbar { width:3px; }\n    .history-list[_ngcontent-%COMP%]::-webkit-scrollbar-thumb { background:var(--neon); opacity:0.3; border-radius:2px; }\n    .history-item[_ngcontent-%COMP%] { display:flex; align-items:center; justify-content:space-between; padding:0.6rem 0; border-bottom:1px solid rgba(0,255,231,0.06); font-size:0.8rem; }\n    .history-item[_ngcontent-%COMP%]:last-child { border-bottom:none; }\n    .hist-name[_ngcontent-%COMP%]   { color:rgba(200,230,227,0.7); letter-spacing:1px; }\n    .hist-angles[_ngcontent-%COMP%] { font-family:'Share Tech Mono',monospace; font-size:0.7rem; color:rgba(0,255,231,0.5); letter-spacing:1px; }\n    .hist-time[_ngcontent-%COMP%]   { font-size:0.65rem; color:rgba(200,230,227,0.25); }\n    .hist-empty[_ngcontent-%COMP%]  { font-size:0.75rem; color:rgba(200,230,227,0.2); letter-spacing:2px; text-align:center; padding:1rem; }\n\n    .cmd-panel[_ngcontent-%COMP%] { grid-column:2; grid-row:2; }\n    .cmd-row[_ngcontent-%COMP%]   { display:flex; gap:1rem; flex-wrap:wrap; margin-bottom:1rem; }\n    .cmd-btn[_ngcontent-%COMP%] { padding:0.7re